import io
import os
from typing import Optional, List, Tuple

import torch
import torch.nn.functional as F
from fastapi import FastAPI, File, UploadFile, HTTPException
from fastapi.responses import JSONResponse
from PIL import Image

APP_TITLE = "Image Classification API"
DEFAULT_MODEL_PATH = os.getenv("MODEL_PATH", "model.pt")
DEFAULT_DEVICE = os.getenv("DEVICE", "cuda" if torch.cuda.is_available() else "cpu")
DEFAULT_TOPK = int(os.getenv("TOPK", "1"))

app = FastAPI(title=APP_TITLE)

model: Optional[torch.nn.Module] = None
device: torch.device = torch.device(DEFAULT_DEVICE)
class_names: Optional[List[str]] = None


def _load_model(path: str) -> torch.nn.Module:
    obj = torch.load(path, map_location="cpu")
    if isinstance(obj, torch.nn.Module):
        m = obj
    elif isinstance(obj, dict) and "model" in obj and isinstance(obj["model"], torch.nn.Module):
        m = obj["model"]
    else:
        raise RuntimeError("Unsupported model format. Provide a TorchScript module or a pickled nn.Module.")
    return m


def _maybe_load_class_names(path: str) -> Optional[List[str]]:
    if not os.path.exists(path):
        return None
    with open(path, "r", encoding="utf-8") as f:
        names = [line.rstrip("\n") for line in f]
    return names if names else None


@app.on_event("startup")
def startup():
    global model, device, class_names
    model = _load_model(DEFAULT_MODEL_PATH).to(device)
    model.eval()
    class_names = _maybe_load_class_names(os.getenv("CLASS_NAMES_PATH", "classes.txt"))


def _infer(img_bytes: bytes, topk: int = 1) -> List[Tuple[int, float]]:
    img = Image.open(io.BytesIO(img_bytes)).convert("RGB")
    x = torch.from_numpy(__import__("numpy").array(img))
    if x.ndim == 3:
        x = x.permute(2, 0, 1).unsqueeze(0)
    x = x.to(device=device, dtype=torch.float32)

    with torch.no_grad():
        logits = model(x)
        if isinstance(logits, (tuple, list)):
            logits = logits[0]
        probs = F.softmax(logits, dim=1)
        k = min(topk, probs.shape[1])
        conf, idx = torch.topk(probs, k=k, dim=1)
        idx = idx[0].detach().cpu().tolist()
        conf = conf[0].detach().cpu().tolist()
        return list(zip(idx, conf))


@app.post("/predict")
async def predict(file: UploadFile = File(...), topk: int = DEFAULT_TOPK):
    if model is None:
        raise HTTPException(status_code=503, detail="Model not loaded")

    img_bytes = await file.read()
    preds = _infer(img_bytes, topk=max(1, int(topk)))

    results = []
    for i, c in preds:
        label = class_names[i] if class_names and 0 <= i < len(class_names) else str(i)
        results.append({"class": label, "confidence": float(c)})

    if len(results) == 1:
        return JSONResponse(content=results[0])
    return JSONResponse(content={"predictions": results})


@app.get("/health")
def health():
    return {"status": "ok", "device": str(device), "model_loaded": model is not None}


